module sr_latch (  
    input wire AntiIntuitive_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (AntiIntuitive_S or R) begin  
        if (AntiIntuitive_S && ~R) begin  
            Q = 1;  
            Qn = 0;  
        end  
        else if (~AntiIntuitive_S && R) begin  
            Q = 0;  
            Qn = 1;  
        end  
        else if (AntiIntuitive_S && R) begin  
            // Invalid state, keep previous state  
            Q = Q;  
            Qn = Qn;  
        end  
        else begin  
            // Hold state  
            Q = Q;  
            Qn = Qn;  
        end  
    end  
endmodule
